INSERT INTO core_news (id, title, slug, content, image, is_published, created_at, updated_at, author_id) VALUES
    (1, 'Открыт прием документов на 2026 год', 'opened-admission-2026', 'Абитуриенты могут подать заявление через личный кабинет, выбрать направление подготовки и загрузить документы онлайн. Приемная комиссия проверяет заявки в рабочие дни.', '', TRUE, '2026-05-10T08:00:00Z', '2026-05-10T08:00:00Z', 150),
    (2, 'Опубликовано расписание вступительных испытаний', 'exam-schedule-2026', 'На странице сроков приема доступно расписание вступительных испытаний по ключевым направлениям. Просим абитуриентов заранее проверить дату, формат и место проведения экзамена.', '', TRUE, '2026-05-11T09:00:00Z', '2026-05-11T09:00:00Z', 150),
    (3, 'Добавлены шаблоны заявлений и согласий', 'document-templates-2026', 'В разделе документов появились актуальные шаблоны заявления, согласия на обработку персональных данных и памятка абитуриента. Файлы можно скачать до подачи заявки.', '', TRUE, '2026-05-12T10:00:00Z', '2026-05-12T10:00:00Z', 150),
    (4, 'Методисты начали проверку первых заявок', 'applications-review-started', 'Первые заявления уже поступили в систему. Статус каждой заявки отображается в личном кабинете абитуриента и обновляется после проверки документов.', '', TRUE, '2026-05-13T11:00:00Z', '2026-05-13T11:00:00Z', 150),
    (5, 'Консультации приемной комиссии доступны онлайн', 'online-consultations-2026', 'Абитуриенты могут обратиться в приемную комиссию по телефону, электронной почте или через онлайн-консультацию. Специалисты помогут выбрать программу и разобраться с документами.', '', TRUE, '2026-05-14T12:00:00Z', '2026-05-14T12:00:00Z', 150)
INSERT INTO core_faq (id, question, answer, "order", is_active) VALUES
    (1, 'Как подать заявление?', 'Создайте личный кабинет, выберите направление подготовки и отправьте заявку. После отправки она появится у методиста на проверке.', 1, TRUE),
    (2, 'Можно ли загрузить документы онлайн?', 'Да, документы прикрепляются к конкретной заявке в личном кабинете. Методист увидит их в разделе проверки документов.', 2, TRUE),
    (3, 'Как узнать статус заявки?', 'Статус заявки отображается в личном кабинете абитуриента: подана, на рассмотрении, принята или отклонена.', 3, TRUE),
    (4, 'Нужны ли оригиналы документов?', 'Для предварительной проверки достаточно электронных копий. Оригиналы предоставляются в приемную комиссию в сроки, указанные в правилах приема.', 4, TRUE),
    (5, 'Можно ли подать несколько заявок?', 'Да, абитуриент может подать заявки на несколько программ, если это не противоречит правилам текущей приемной кампании.', 5, TRUE),
    (6, 'Где посмотреть вступительные испытания?', 'Актуальные даты, аудитории и форматы испытаний размещены в разделе «Сроки и расписание».', 6, TRUE),
    (7, 'Как связаться с приемной комиссией?', 'Контакты, телефон, email и часы работы опубликованы на странице «Контакты».', 7, TRUE),
    (8, 'Когда появятся результаты экзаменов?', 'После проверки методист внесет результаты в систему, и они появятся в личном кабинете абитуриента.', 8, TRUE)
